import CryptoKit

class PasswordStorage {

    private let salt = "your_salt"

    func hashPassword(_ password: String) -> String {
        let passwordData = password.data(using: .utf8)!
        let saltData = salt.data(using: .utf8)!
        let combinedData = passwordData + saltData

        let digest = Insecure.MD5.hash(combinedData).map { String(format: "%02x", $0) }.joined()

        return digest
    }

    func verifyPassword(_ password: String, hashedPassword: String) -> Bool {
        let hashedPasswordToCheck = hashPassword(password)
        return hashedPasswordToCheck == hashedPassword
